from functools import wraps
import time

def timer(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        print(f"Time: {time.time()-start:.0f}s")
        return result
    return wrapper

@timer
def slow_function(n):
    return sum(range(n))

result = slow_function(1000000)
print(result)

