import numpy as np

class Vocab:
    def __init__(self, texts):
        words = set()
        for t in texts:
            words.update(t.split())
        self.word2id = {w:i for i,w in enumerate(sorted(words))}

    def encode(self, text):
        return [self.word2id.get(w, -1) for w in text.split()]

vocab = Vocab(["tôi học AI", "AI rất hay"])
print(vocab.encode("AI hay"))

