def dcg_at_k(relevances, k):
    dcg = 0
    for i, rel in enumerate(relevances[:k]):
        dcg += rel / np.log2(i + 2)  # i+2 vì log2(1)=0
    return dcg

def ndcg_at_k(predicted_relevances, ideal_relevances, k):
    return dcg_at_k(predicted_relevances, k) / dcg_at_k(ideal_relevances, k)

