def pad_sequences(sequences, max_len, pad_value=0):
    padded = []
    for seq in sequences:
        if len(seq) > max_len:
            padded.append(seq[:max_len])  # truncate
        else:
            padded.append(seq + [pad_value] * (max_len - len(seq)))  # pad
    return np.array(padded)

