class SentenceWindowRetriever:
    def __init__(self, window_size=2):
        self.window_size = window_size

    def retrieve_with_context(self, chunk_idx, all_sentences):
        start = max(0, chunk_idx - self.window_size)
        end = min(len(all_sentences), chunk_idx + self.window_size + 1)
        return all_sentences[start:end]

